mapper.select:

SELECT COUNT(*) AS CNT
FROM TB_USER TU
WHERE TU.EMAIL = #{email}

mapper.insert:
INSERT INTO TB_USER
(
    USER_SEQ
,   EMAIL
,   PWD
,   USER_NM
,   PRO_IMG
,   CREATE_DATE
,   CREATE_USER_SEQ
,   UPDATE_DATE
,   UPDATE_USER_SEQ
) VALUES (
    (
      SELECT (CASE WHEN MAX(USER_SEQ) IS NULL THEN 0 ELSE MAX(USER_SEQ) END) + 1
      FROM TB_USER
      WHERE USER_SEQ <> 99999
    )
,   #{email}
,   #{pwd}
,   #{userNm}
,   #{proImg}
,   CURRENT_TIMESTAMP
,   #{createUserSeq}
,   CURRENT_TIMESTAMP
,   #{updateUserSeq}
)
